4243   //   EMIT vp<%at.cond.1> = extract-lane vp<%first.lane>, vp<%cond.1>
4244   //   EMIT branch-on-cond vp<%at.cond.1>
4245   // Successor(s): vector.early.exit.1, vector.early.exit.2
4246   VPBasicBlock *CurrentBB = DispatchVPBB;
4247   for (auto [I, Exit] : enumerate(ArrayRef(Exits).drop_back())) {
