1859   // need to make PHI nodes for other users. That can be done once the initial
1860   // transform code lands.
1861   auto *Br = cast<BranchInst>(ExitingBlock->getTerminator());
1862 
1863   using namespace llvm::PatternMatch;
1864   Instruction *L = nullptr;
1865   Value *Ptr = nullptr;
1866   Value *R = nullptr;
1867   if (!match(Br->getCondition(),
1868              m_OneUse(m_ICmp(m_OneUse(m_Instruction(L, m_Load(m_Value(Ptr)))),
1869                              m_Value(R))))) {
1870     reportVectorizationFailure(
1871         "Early exit loop with store but no supported condition load",
1872         "NoConditionLoadForEarlyExitLoop", ORE, TheLoop);
1873     return false;
1874   }
1875 
