1877   if (!TheLoop->isLoopInvariant(R)) {
1878     reportVectorizationFailure(
1879         "Early exit loop with store but no supported condition load",
1880         "NoConditionLoadForEarlyExitLoop", ORE, TheLoop);
1881     return false;
1882   }
