1888     reportVectorizationFailure(
1889         "Uncountable exit condition depends on load with an address that is "
1890         "not an add recurrence in the loop",
1891         "EarlyExitLoadInvariantAddress", ORE, TheLoop);
1892     return false;
1893   }
1894 
