4083       auto *EarlyExitingVPBB = cast<VPBasicBlock>(Pred);
4084       VPBlockBase *TrueSucc = EarlyExitingVPBB->getSuccessors()[0];
4085       VPValue *CondOfEarlyExitingVPBB;
4086       [[maybe_unused]] bool Matched =
4087           match(EarlyExitingVPBB->getTerminator(),
4088                 m_BranchOnCond(m_VPValue(CondOfEarlyExitingVPBB)));
4089       assert(Matched && "Terminator must be BranchOnCond");
4090 
4091       // Insert the MaskedCond in the EarlyExitingVPBB so the predicator adds
4092       // the correct block mask.
4093       VPBuilder EarlyExitingBuilder(EarlyExitingVPBB->getTerminator());
4094       auto *CondToEarlyExit = EarlyExitingBuilder.createNaryOp(
4095           VPInstruction::MaskedCond,
4096           TrueSucc == ExitBlock
4097               ? CondOfEarlyExitingVPBB
4098               : EarlyExitingBuilder.createNot(CondOfEarlyExitingVPBB));
4099       assert((isa<VPIRValue>(CondOfEarlyExitingVPBB) ||
4100               !VPDT.properlyDominates(EarlyExitingVPBB, LatchVPBB) ||
4101               VPDT.properlyDominates(
4102                   CondOfEarlyExitingVPBB->getDefiningRecipe()->getParent(),
4103                   LatchVPBB)) &&
4104              "exit condition must dominate the latch");
