4106           EarlyExitingVPBB,
4107           ExitBlock,
4108           CondToEarlyExit,
4109       });
4110     }
4111   }
4112 
4113   assert(!Exits.empty() && "must have at least one early exit");
4114   // Sort exits by RPO order to get correct program order. RPO gives a
4115   // topological ordering of the CFG, ensuring upstream exits are checked
4116   // before downstream exits in the dispatch chain.
4117   ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>> RPOT(
4118       HeaderVPBB);
