4123     return RPOIdx[A.EarlyExitingVPBB] < RPOIdx[B.EarlyExitingVPBB];
4124   });
4125 #ifndef NDEBUG
4126   // After RPO sorting, verify that for any pair where one exit dominates
4127   // another, the dominating exit comes first. This is guaranteed by RPO
4128   // (topological order) and is required for the dispatch chain correctness.
4129   for (unsigned I = 0; I + 1 < Exits.size(); ++I)
4130     for (unsigned J = I + 1; J < Exits.size(); ++J)
4131       assert(!VPDT.properlyDominates(Exits[J].EarlyExitingVPBB,
