4147   SmallVector<VPBasicBlock *> VectorEarlyExitVPBBs(Exits.size());
4148   for (unsigned Idx = 0; Idx != Exits.size(); ++Idx) {
4149     Twine BlockSuffix = Exits.size() == 1 ? "" : Twine(".") + Twine(Idx);
