4167   // For each early exit, disconnect the original exiting block
4168   // (early.exiting.I) from the exit block (ir-bb<exit.I>) and route through a
4169   // new vector.early.exit block. Update ir-bb<exit.I>'s phis to extract their
4170   // values at the first active lane:
4171   //
4172   // Input:
4173   //  early.exiting.I:
4174   //     ...
4175   //    EMIT branch-on-cond vp<%cond.I>
4176   //  Successor(s): in.loop.succ, ir-bb<exit.I>
4177   //
4178   //  ir-bb<exit.I>:
4179   //    IR %phi = phi [ vp<%incoming.I>, early.exiting.I ], ...
4180   //
4181   // Output:
4182   //  early.exiting.I:
4183   //    ...
4184   //  Successor(s): in.loop.succ
4185   //
4186   //  vector.early.exit.I:
4187   //    EMIT vp<%exit.val> = extract-lane vp<%first.lane>, vp<%incoming.I>
4188   //  Successor(s): ir-bb<exit.I>
4189   //
4190   //  ir-bb<exit.I>:
4191   //    IR %phi = phi ... (extra operand: vp<%exit.val> from
4192   //                                      vector.early.exit.I)
4193   //
4194   for (auto [Exit, VectorEarlyExitVPBB] :
4195        zip_equal(Exits, VectorEarlyExitVPBBs)) {
4196     auto &[EarlyExitingVPBB, EarlyExitVPBB, _] = Exit;
4197     // Adjust the phi nodes in EarlyExitVPBB.
4198     //   1. remove incoming values from EarlyExitingVPBB,
4199     //   2. extract the incoming value at FirstActiveLane
4200     //   3. add back the extracts as last operands for the phis
4201     // Then adjust the CFG, removing the edge between EarlyExitingVPBB and
4202     // EarlyExitVPBB and adding a new edge between VectorEarlyExitVPBB and
4203     // EarlyExitVPBB. The extracts at FirstActiveLane are now the incoming
4204     // values from VectorEarlyExitVPBB.
4205     for (VPRecipeBase &R : EarlyExitVPBB->phis()) {
4206       auto *ExitIRI = cast<VPIRPhi>(&R);
4207       VPValue *IncomingVal =
4208           ExitIRI->getIncomingValueForBlock(EarlyExitingVPBB);
4209       VPValue *NewIncoming = IncomingVal;
4210       if (!isa<VPIRValue>(IncomingVal)) {
4211         VPBuilder EarlyExitBuilder(VectorEarlyExitVPBB);
4212         NewIncoming = EarlyExitBuilder.createNaryOp(
4213             VPInstruction::ExtractLane, {FirstActiveLane, IncomingVal},
4214             DebugLoc::getUnknown(), "early.exit.value");
4215       }
4216       ExitIRI->removeIncomingValueFor(EarlyExitingVPBB);
4217       ExitIRI->addOperand(NewIncoming);
4218     }
4219 
4220     EarlyExitingVPBB->getTerminator()->eraseFromParent();
4221     VPBlockUtils::disconnectBlocks(EarlyExitingVPBB, EarlyExitVPBB);
4222     VPBlockUtils::connectBlocks(VectorEarlyExitVPBB, EarlyExitVPBB);
4223   }
4224 
4225   // Chain through exits: for each exit, check if its condition is true at
4226   // the first active lane. If so, take that exit; otherwise, try the next.
4227   // The last exit needs no check since it must be taken if all others fail.
4228   //
4229   // For 3 exits (cond.0, cond.1, cond.2), this creates:
4230   //
4231   // latch:
4232   //   ...
4233   //   EMIT vp<%combined> = logical-or vp<%cond.0>, vp<%cond.1>, vp<%cond.2>
4234   //   ...
4235   //
4236   // vector.early.exit.check:
4237   //   EMIT vp<%first.lane> = first-active-lane vp<%combined>
4238   //   EMIT vp<%at.cond.0> = extract-lane vp<%first.lane>, vp<%cond.0>
4239   //   EMIT branch-on-cond vp<%at.cond.0>
